// Check a specific failure
if (input.validity.valueMissing) {
  console.log('Email is required');
} else if (input.validity.typeMismatch) {
  console.log('Not a valid email address');
}

// Check all at once
if (input.validity.valid) {
  console.log('All constraints pass');
}

// input.validationMessage is the browser's localized error string
console.log(input.validationMessage);
// e.g. "Please fill out this field" / "Please include an '@' in the email address."

const form  = document.getElementById('signup');
const email = document.getElementById('email');

// checkValidity() — returns boolean, fires 'invalid' event on failure
//   Does NOT show browser error bubbles
if (!email.checkValidity()) {
  console.log('Email invalid:', email.validationMessage);
}

// reportValidity() — same as checkValidity() but ALSO shows browser tooltips
//   Returns boolean like checkValidity()
if (!form.reportValidity()) {
  // Browser shows bubble on first invalid field
  console.log('Form has errors');
}

// On the form element, both methods check ALL child controls
//   and return false if any fail
const allValid = form.checkValidity();

const username = document.getElementById('username');

// Validate on input
username.addEventListener('input', async () => {
  // First clear any previous custom error so other validators run
  username.setCustomValidity('');

  if (username.validity.valid) {
    // Only check uniqueness if all attribute constraints pass
    const taken = await checkUsernameAvailability(username.value);
    if (taken) {
      username.setCustomValidity('This username is already taken.');
    }
  }
});

