/* :valid and :invalid match immediately — including on empty required fields */
input:valid   { border-color: #16a34a; }
input:invalid { border-color: #dc2626; }

/* Problematic: empty required fields are :invalid on page load */
/* Better approach: only show error style after user interaction */
input:user-invalid { border-color: #dc2626; }   /* modern browsers */

/* Fallback: add a class after submission attempt */
form.submitted input:invalid { border-color: #dc2626; }

/* Style required and optional fields */
input:required { background: #fefce8; }   /* light yellow hint */
input:optional { background: #fff; }

/* in-range and out-of-range for number/date/range inputs */
input:in-range   { border-color: #16a34a; }
input:out-of-range { border-color: #dc2626; }

/* Modern, flicker-free validation styling */
input:user-invalid {
  border-color: #dc2626;
  outline-color: #dc2626;
}

input:user-invalid + .error-message {
  display: block;   /* show sibling error message */
}

.error-message {
  display: none;
  color: #dc2626;
  font-size: 0.75rem;
  margin-top: 0.25rem;
}

// Angular adds novalidate automatically when FormsModule or
// ReactiveFormsModule is imported and a form directive is applied.
// You can also add it explicitly without harming Angular's behavior.

// Using the ngForm directive (template-driven):
// <form #f="ngForm" ...> — novalidate auto-added

// Using [formGroup] (reactive):
// <form [formGroup]="form" ...> — novalidate auto-added

// If you want browser validation bubbles in a non-Angular form:
// simply omit novalidate (the default is validation enabled)

import {
  FormControl, FormGroup, Validators, ReactiveFormsModule
} from '@angular/forms';
import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'app-signup',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule],
  template: `
    <form [formGroup]="form" (ngSubmit)="submit()" novalidate>

      <label for="email">Email *</label>
      <input id="email" type="email" formControlName="email" />
      <div *ngIf="showErr('email')" class="error">
        <span *ngIf="form.get('email')?.errors?.['required']">Email is required.</span>
        <span *ngIf="form.get('email')?.errors?.['email']">Not a valid email address.</span>
      </div>

      <label for="pw">Password * (8–64 characters)</label>
      <input id="pw" type="password" formControlName="password" />
      <div *ngIf="showErr('password')" class="error">
        <span *ngIf="form.get('password')?.errors?.['required']">Password is required.</span>
        <span *ngIf="form.get('password')?.errors?.['minlength']">
          Minimum 8 characters.
        </span>
      </div>

      <label for="age">Age (18-120) *</label>
      <input id="age" type="number" formControlName="age" />
      <div *ngIf="showErr('age')" class="error">
        <span *ngIf="form.get('age')?.errors?.['min']">Must be at least 18.</span>
        <span *ngIf="form.get('age')?.errors?.['max']">Maximum age 120.</span>
      </div>

      <button type="submit" [disabled]="form.invalid">Create account</button>
    </form>
  `,
})
export class SignupComponent {
  form = new FormGroup({
    email:    new FormControl('', [Validators.required, Validators.email]),
    password: new FormControl('', [Validators.required, Validators.minLength(8), Validators.maxLength(64)]),
    age:      new FormControl<number | null>(null, [Validators.required, Validators.min(18), Validators.max(120)]),
  });

  showErr(name: string): boolean {
    const c = this.form.get(name);
    return !!(c?.invalid && c?.touched);
  }

  submit(): void {
    this.form.markAllAsTouched();
    if (this.form.invalid) return;
    console.log('Valid data:', this.form.value);
  }
}

// Pattern: suppress browser bubbles, show custom messages on submit
const form = document.querySelector('form');

form.addEventListener('submit', (e) => {
  e.preventDefault();
  if (!form.checkValidity()) {
    // Show custom messages for all invalid fields
    form.querySelectorAll(':invalid').forEach(input => {
      showError(input, input.validationMessage);
    });
    return;
  }
  // Proceed with valid data
  submitForm(new FormData(form));
});

function showError(input, message) {
  const errorEl = document.getElementById(`${input.id}-error`);
  if (errorEl) {
    errorEl.textContent = message;
    errorEl.hidden = false;
  }
  input.setAttribute('aria-invalid', 'true');
  input.setAttribute('aria-describedby', `${input.id}-error`);
}

function clearError(input) {
  const errorEl = document.getElementById(`${input.id}-error`);
  if (errorEl) { errorEl.hidden = true; }
  input.removeAttribute('aria-invalid');
}

// Clear error when user fixes the input
form.querySelectorAll('input').forEach(input => {
  input.addEventListener('input', () => {
    if (input.validity.valid) clearError(input);
  });
});

const input = document.getElementById('email');

input.addEventListener('invalid', (e) => {
  // Suppress browser tooltip
  e.preventDefault();

  // Show your own error UI
  const msg = input.validity.valueMissing
    ? 'Email is required.'
    : 'Please enter a valid email address.';

  document.getElementById('email-error').textContent = msg;
});

// The invalid event is NOT a continuous stream — it fires once on
// checkValidity() / form submission, not on every keystroke.
// Listen to 'input' events to clear errors as the user corrects.
input.addEventListener('input', () => {
  if (input.validity.valid) {
    document.getElementById('email-error').textContent = '';
  }
});

// Playwright end-to-end test
import { test, expect } from '@playwright/test';

test('signup form blocks submission with empty fields', async ({ page }) => {
  await page.goto('/signup');
  await page.click('button[type=submit]');

  // Check custom error message is visible
  await expect(page.locator('#email-error')).toBeVisible();
  await expect(page.locator('#email-error')).toHaveText(/required/i);
});

test('email field rejects invalid format', async ({ page }) => {
  await page.goto('/signup');
  await page.fill('#email', 'not-an-email');
  await page.click('button[type=submit]');
  await expect(page.locator('#email-error')).toContainText(/valid email/i);
});

test('valid form submits successfully', async ({ page }) => {
  await page.goto('/signup');
  await page.fill('#email', 'user@example.com');
  await page.fill('#pw',    'securePassword1');
  await page.click('button[type=submit]');
  await expect(page).toHaveURL('/dashboard');
});
